    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        if userActivity.activityType == NSUserActivityTypeBrowsingWeb,
           let url = userActivity.webpageURL {
            handleUniversalLink(url)
        }
        return true
    }
    
    private func handleUniversalLink(_ url: URL) {
        guard url.host == "myapp.com" && url.path == "/promo" else { return }
        
        let promoCode = extractParameter(from: url, parameter: "code")
        let discount = extractParameter(from: url, parameter: "discount")
        
        if let code = promoCode, let discountValue = Int(discount ?? "0") {
            applyPromoCode(code, discount: discountValue)
        }
    }
    
    private func extractParameter(from url: URL, parameter: String) -> String? {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
              let queryItems = components.queryItems else { return nil }
        
        return queryItems.first(where: { $0.name == parameter })?.value
    }
    
    private func applyPromoCode(_ code: String, discount: Int) {
        // Simulate applying promo code to user account
        print("Applying promo code: \(code) with discount: \(discount)%")
        
        // Here you would typically:
        // 1. Store the promo code in user defaults or database
        // 2. Apply discount to user's account
        // 3. Update UI to show discount applied
        // 4. Send confirmation to server
        
        UserDefaults.standard.set(code, forKey: "ActivePromoCode")
        UserDefaults.standard.set(discount, forKey: "ActivePromoDiscount")
        
        // Notify UI that promo was applied
        NotificationCenter.default.post(name: NSNotification.Name("PromoCodeApplied"), object: nil)
    }
