class ViewController: UIViewController {
    @IBOutlet weak var promoCodeLabel: UILabel!
    @IBOutlet weak var discountLabel: UILabel!
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupNotifications()
        loadSavedPromo()
    }
    
    private func setupNotifications() {
        NotificationCenter.default.addObserver(
            self,
            selector: #selector(promoCodeApplied),
            name: NSNotification.Name("PromoCodeApplied"),
            object: nil
        )
    }
    
    @objc private func promoCodeApplied() {
        loadSavedPromo()
    }
    
    private func loadSavedPromo() {
        if let code = UserDefaults.standard.string(forKey: "ActivePromoCode"),
           let discount = UserDefaults.standard.object(forKey: "ActivePromoDiscount") as? Int {
            promoCodeLabel.text = "Promo Code: \(code)"
            discountLabel.text = "Discount: \(discount)%"
        }
    }
    
    deinit {
        NotificationCenter.default.removeObserver(self)
    }
